// Enhanced application with security best practices
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const mongoSanitize = require('express-mongo-sanitize');
const xss = require('xss-clean');
const { v4: uuidv4 } = require('uuid');

const app = express();

// Security Middleware (apply BEFORE routes)
app.use(helmet());
app.use(express.json({ limit: '10mb' })); // Limit payload size
app.use(mongoSanitize()); // Prevent NoSQL injection
app.use(xss()); // Sanitize against XSS

// CORS Configuration
app.use((req, res, next) => {
  res.header('Access-Control-Allow-Origin', process.env.ALLOWED_ORIGINS || 'http://localhost:3000');
  res.header('Access-Control-Allow-Headers', 'Content-Type, Authorization');
  res.header('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE');
  next();
});

// Rate Limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// Request ID for tracking
app.use((req, res, next) => {
  req.id = uuidv4();
  next();
});

// Input validation middleware
const validateQueryParams = (req, res, next) => {
  // Validate query parameters to prevent injection
  const { limit, offset } = req.query;

  if (limit && (isNaN(limit) || parseInt(limit) < 1 || parseInt(limit) > 1000)) {
    return res.status(400).json({ 
      error: 'Invalid limit parameter. Must be 1-1000.' 
    });
  }

  if (offset && (isNaN(offset) || parseInt(offset) < 0)) {
    return res.status(400).json({ 
      error: 'Invalid offset parameter. Must be >= 0.' 
    });
  }

  next();
};

// Health Check Endpoint
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      requestId: req.id
    });
  } catch (error) {
    logError('Health check error', error, req.id);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Users Endpoint with validation
app.get('/users', validateQueryParams, (req, res) => {
  try {
    const limit = Math.min(parseInt(req.query.limit) || 10, 100);
    const offset = Math.max(parseInt(req.query.offset) || 0, 0);

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    const paginatedUsers = users.slice(offset, offset + limit);

    res.json({
      data: paginatedUsers,
      meta: {
        total: users.length,
        limit,
        offset,
        requestId: req.id
      }
    });
  } catch (error) {
    logError('Users endpoint error', error, req.id);
    res.status(500).json({ error: 'Failed to fetch users' });
  }
});

// 404 Handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// Error Handling Middleware (must be last)
app.use((err, req, res, next) => {
  logError('Unhandled error', err, req.id);

  const statusCode = err.statusCode || 500;
  const message = process.env.NODE_ENV === 'production' 
    ? 'Internal server error' 
    : err.message;

  res.status(statusCode).json({ 
    error: message,
    requestId: req.id
  });
});

// Simple logging function
function logError(message, error, requestId) {
  console.error(`[${requestId}] ${message}:`, error.message);
}

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

### **Required Dependencies to Add**

```bash
npm install helmet express-rate-limit express-mongo-sanitize xss-clean uuid
```

